        continue
    t=o.get('type')
    tool=o.get('tool')
    if t=='code_change':
        old=o.get('old_text','')[:80].replace(chr(10),' ')
        new=o.get('new_text','')[:120].replace(chr(10),' ')
        print(f\"[EDIT] old={old!r}\")
        print(f\"       new={new!r}\")
    elif t=='diagnostics':
        print(f\"[DIAG] errs={o.get('error_count')} warns={o.get('warning_count')} firsterr={str(o.get('errors'))[:160]}\")
    elif t=='goal_state':
        g=o.get('goal','')[:120].replace(chr(10),' ')
        print(f\"[GOAL] line={o.get('line')} {g!r}\")
    elif t=='lemma_search':
        print(f\"[SEARCH] {o.get('query')}\")
    elif t=='lean_other':
        print(f\"[ATTEMPT] {str(o.get('result_preview',''))[:100]!r}\")
    elif t=='file_read':
        pass
    else:
        print(f\"[{t}] {tool}\")
"

